# Generated by openai (gpt-5.2)
# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

import os
import json
import joblib
from typing import Optional

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from sklearn.pipeline import Pipeline
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression


DEFAULT_MODEL_PATH = os.environ.get("SPAM_MODEL_PATH", "spam_model.joblib")


class TrainRequest(BaseModel):
    texts: list[str] = Field(..., min_length=2)
    labels: list[int] = Field(..., min_length=2, description="0=ham, 1=spam")
    C: float = 1.0
    max_features: Optional[int] = 50000
    ngram_max: int = 1
    lowercase: bool = True


class PredictRequest(BaseModel):
    text: str = Field(..., min_length=1)


class PredictResponse(BaseModel):
    spam_probability: float
    is_spam: bool
    threshold: float


def build_pipeline(C: float = 1.0, max_features: Optional[int] = 50000, ngram_max: int = 1, lowercase: bool = True) -> Pipeline:
    return Pipeline(
        steps=[
            (
                "vect",
                CountVectorizer(
                    lowercase=lowercase,
                    max_features=max_features,
                    ngram_range=(1, max(1, int(ngram_max))),
                ),
            ),
            ("clf", LogisticRegression(C=C, max_iter=2000, solver="liblinear")),
        ]
    )


def load_model(path: str) -> Pipeline:
    if not os.path.exists(path):
        raise FileNotFoundError(path)
    model = joblib.load(path)
    if not hasattr(model, "predict_proba"):
        raise ValueError("Loaded object is not a compatible sklearn model.")
    return model


def save_model(model: Pipeline, path: str) -> None:
    joblib.dump(model, path)


app = FastAPI(title="Spam Detection API", version="1.0.0")
_model: Optional[Pipeline] = None


@app.on_event("startup")
def _startup():
    global _model
    try:
        _model = load_model(DEFAULT_MODEL_PATH)
    except Exception:
        _model = None


@app.get("/health")
def health():
    return {"status": "ok", "model_loaded": _model is not None, "model_path": DEFAULT_MODEL_PATH}


@app.post("/train")
def train(req: TrainRequest):
    if len(req.texts) != len(req.labels):
        raise HTTPException(status_code=400, detail="texts and labels must be the same length")
    if any(y not in (0, 1) for y in req.labels):
        raise HTTPException(status_code=400, detail="labels must be 0 or 1")

    model = build_pipeline(C=req.C, max_features=req.max_features, ngram_max=req.ngram_max, lowercase=req.lowercase)
    model.fit(req.texts, req.labels)

    save_model(model, DEFAULT_MODEL_PATH)
    global _model
    _model = model

    return {"trained": True, "saved_to": DEFAULT_MODEL_PATH, "n_samples": len(req.texts)}


@app.post("/predict", response_model=PredictResponse)
def predict(req: PredictRequest, threshold: float = 0.5):
    if not (0.0 < threshold < 1.0):
        raise HTTPException(status_code=400, detail="threshold must be between 0 and 1")

    global _model
    if _model is None:
        try:
            _model = load_model(DEFAULT_MODEL_PATH)
        except Exception:
            raise HTTPException(status_code=503, detail="Model not available. Train first or provide a valid model file.")

    proba = float(_model.predict_proba([req.text])[0][1])
    return PredictResponse(spam_probability=proba, is_spam=proba >= threshold, threshold=threshold)


@app.post("/reload")
def reload_model():
    global _model
    _model = load_model(DEFAULT_MODEL_PATH)
    return {"reloaded": True, "model_path": DEFAULT_MODEL_PATH}


if __name__ == "__main__":
    import uvicorn

    host = os.environ.get("HOST", "0.0.0.0")
    port = int(os.environ.get("PORT", "8000"))
    uvicorn.run(app, host=host, port=port)